    def test_cli_research_tms_and_oddballs_smoke(self):
        repo_root = self._repo_root()
        main_script = repo_root / "py" / "main_accgram.py"
        troubles_in = repo_root / "out" / "accgram" / "goerwitz" / "_troublemakers.json"

        self.assertTrue(main_script.exists(), f"Missing entrypoint: {main_script}")
        self.assertTrue(
            troubles_in.exists(),
            "Expected goerwitz troublemakers input to exist before smoke run.",
        )

        with TemporaryDirectory() as tmp_dir:
            base = Path(tmp_dir)
            out_path = base / "out" / "research-troublemakers.json"
            oddballs_out_path = base / "out" / "research-oddballs.json"
            html_out_path = base / "gh-pages" / "accgram" / "goerwitz-tms.html"

            completed = subprocess.run(
                [
                    sys.executable,
                    str(main_script),
                    "research-tms-and-oddballs",
                    "--out",
                    str(out_path),
                    "--oddballs-out",
                    str(oddballs_out_path),
                    "--html-out",
                    str(html_out_path),
                ],
                cwd=repo_root,
                capture_output=True,
                text=True,
                encoding="utf-8",
                errors="replace",
                check=False,
            )

            self.assertEqual(
                completed.returncode,
                0,
                "research-tms-and-oddballs CLI failed"
                f"\nstdout:\n{completed.stdout}\n"
                f"stderr:\n{completed.stderr}",
            )
            self.assertTrue(out_path.exists(), f"Missing output JSON: {out_path}")
            self.assertTrue(
                oddballs_out_path.exists(), f"Missing oddballs output JSON: {oddballs_out_path}"
            )
            self.assertTrue(html_out_path.exists(), f"Missing HTML report: {html_out_path}")

            payload = json.loads(out_path.read_text(encoding="utf-8"))
            self.assertIn("troublemakers", payload)
            self.assertGreaterEqual(len(payload["troublemakers"]), 1)

    def _assert_generated_goerwitz_contracts(
        self, page_path: Path
    ) -> list[rtmsr_contracts.GoerwitzTroublemakerSection]:
        self.assertTrue(
            page_path.exists(), f"Missing generated report page: {page_path}"
        )

        sections = rtmsr_contracts.inspect_goerwitz_tms_html_contracts(
            page_path.read_text(encoding="utf-8")
        )
        self.assertGreater(
            len(sections),
            0,
            f"Expected at least one troublemaker section in {page_path.name}",
        )

        for section in sections:
            msg_prefix = f"{page_path.name} [{section.ref}]"
            self.assertTrue(
                section.has_verse_paragraph,
                f"{msg_prefix}: missing goerwitz verse paragraph",
            )
            self.assertTrue(
                section.has_sat_table,
                f"{msg_prefix}: missing goerwitz SAT table",
            )
            self.assertTrue(
                section.verse_before_sat,
                f"{msg_prefix}: verse paragraph must appear before SAT table",
            )
            self.assertNotIn(
                "wlc_before",
                section.sat_keys,
                f"{msg_prefix}: SAT key wlc_before must not be rendered",
            )
            self.assertNotIn(
                "wlc_after",
                section.sat_keys,
                f"{msg_prefix}: SAT key wlc_after must not be rendered",
            )

            non_empty_focus_values = {
                value for value in section.wlc_focus_values if value
            }
            if section.focus_highlights:
                self.assertEqual(
                    len(section.focus_highlights),
                    1,
                    f"{msg_prefix}: expected at most one focus highlight span",
                )

            if non_empty_focus_values and section.focus_highlights:
                self.assertIn(
                    section.focus_highlights[0],
                    non_empty_focus_values,
                    f"{msg_prefix}: highlighted focus does not match SAT wlc_focus value",
                )

        return sections

