    def test_to_xmlish_word_preserves_text_after_inline_x_child(self):
        element = ET.fromstring("<w>פֶ֛<x>t</x>לִאי׃</w>")

        node = research_tms._to_xmlish_verse_child(element)
        node = sanitize_verse_text_payload(node)

        self.assertIsInstance(node, dict)
        self.assertEqual(node, {"text": "פ֛לאי׃", "note": "t"})

    def test_sanitize_keeps_only_last_meteg_in_last_word(self):
        wlc422_verse = {
            "bcv": "gn1:1",
            "vels": ["אֽב", "גֽדֽה"],
        }
        uxlc_nodes = ["אֽב", "גֽדֽה"]

        wlc_clean = sanitize_verse_text_payload(wlc422_verse)
        uxlc_clean = sanitize_verse_text_payload(uxlc_nodes)

        self.assertEqual(wlc_clean["vels"], ["אב", "גדֽה"])
        self.assertEqual(uxlc_clean, ["אב", "גדֽה"])

    def test_sanitize_option_removes_duplicate_telisha_gedola(self):
        node = {"vels": ["א֠ת֠י", "ל֠מ֠ען", "ב֠כנפ֠ו"]}

        default_clean = sanitize_verse_text_payload(node)
        mam_clean = sanitize_verse_text_payload(
            node,
            remove_duplicate_telisha_gedola=True,
        )

        self.assertEqual(default_clean["vels"], ["א֠ת֠י", "ל֠מ֠ען", "ב֠כנפ֠ו"])
        self.assertEqual(mam_clean["vels"], ["א֠תי", "ל֠מען", "ב֠כנפו"])

    def test_sanitize_option_preserve_all_meteg_keeps_interior_meteg(self):
        node = {"vels": ["מֽבלֽי", "ידֽי־"]}

        default_clean = sanitize_verse_text_payload(node)
        witness_clean = sanitize_verse_text_payload(node, preserve_all_meteg=True)

        self.assertEqual(default_clean["vels"], ["מבלי", "ידֽי־"])
        self.assertEqual(witness_clean["vels"], ["מֽבלֽי", "ידֽי־"])

